// xiaoZhiTiaoDefaults — 小纸条默认内置图（2026-07-22：暮色手绘便签）
// 暮色原话："先一张试试"。原图 123.png：1080×1080 RGBA PNG，1MB（透明底手绘爱心边框）
// 暮色要求保留透明底（sips 转 JPEG 会丢 alpha → 白底糊边），所以直接用 PNG base64
// 体积：1.45MB base64 字符串。代码 bundle 会大一点，但图床永远不挂
//
// 用法：getStoredXiaoZhiTiaoStyles 首次访问 / 激活组为空时自动预置这个默认组
//       暮色以后想加图 / 换图：去设置里换 / 加，不动代码

export const DEFAULT_XIAO_ZHI_TIAO_GROUP_NAME = '暮色手绘便签';

export const DEFAULT_XIAO_ZHI_TIAO_IMAGES: string[] = [
    'data:image/png;base64,',
];
